create table dirkspzm32.isi_alert_cfg (
    alert_cfg_name       varchar2(100 char) not null enable,
    alert_intervall      number(10, 0),
    res_id               number(6, 0),
    template_kopf        varchar2(200 char),
    template_meld_kommt  varchar2(200 char),
    template_meld_geht   varchar2(200 char),
    mail_address         varchar2(200 char),
    user_id              number(6, 0),
    created_date         date,
    last_changed_date    date,
    last_changed_user_id number(6, 0),
    alert_aktiv          varchar2(1 char) default 'T' not null enable,
    last_alert_date      date,
    alert_typ            varchar2(1 char) default 'M',
    alert_status         varchar2(1 char) default '-' not null enable,
    alert_datum          date,
    alert_filter         varchar2(150 char)
);

alter table dirkspzm32.isi_alert_cfg
    add constraint chk_isi_alert_cfg_aktiv
        check ( alert_aktiv in ( 'T', 'F', 'M' ) ) enable;

alter table dirkspzm32.isi_alert_cfg
    add constraint chk_isi_alert_cfg_typ
        check ( alert_typ in ( 'R', 'M', 'S' ) ) enable;

alter table dirkspzm32.isi_alert_cfg
    add constraint pk_isi_alert_cfg primary key ( alert_cfg_name )
        using index enable;


